import { NavLink } from "react-router-dom";
import { hasRole } from "../utils/auth";
import { useState } from "react";

export default function Sidebar() {
  const user = JSON.parse(localStorage.getItem("user"));
  const handleLogout = () => {
  localStorage.removeItem("user");
  window.location.href = "/";
};

const [collapsed, setCollapsed] = useState(true);

  const navClass = ({ isActive }) =>
    isActive
      ? "sidebar-link active-link"
      : "sidebar-link";

  return (
    <div className="bg-success text-white p-3 vh-100">
      <h4 className="mb-4">AGV Portal</h4>

      <ul className="nav flex-column">

        <li className="nav-item">
          <NavLink to="/dashboard" className={navClass}>
            <i className="bi bi-speedometer2 me-2"></i>
            <span className="menu-text">Dashboard</span>
          </NavLink>
        </li>

        {hasRole(["super_admin"]) && (

  <li className="nav-item">

    <NavLink to="/companies" className={navClass}>
            <i className="bi bi-speedometer2 me-2"></i>
            <span className="menu-text">Companies</span>
          </NavLink>

  </li>

)}

        <li className="nav-item">
          <NavLink to="/flood" className={navClass}>
            <i className="bi bi-speedometer2 me-2"></i>
            <span className="menu-text">Flood</span>
          </NavLink>
        </li>

        {hasRole(["super_admin", "it_admin"]) && (

        <li className="nav-item">

          <NavLink to="/users" className={navClass}>
            <i className="bi bi-speedometer2 me-2"></i>
            <span className="menu-text">Users</span>
          </NavLink>

        </li>

)}

        {user?.role === "admin" && (
          <li className="nav-item">
            <NavLink to="/users" className={navClass}>
              <i className="bi bi-people me-2"></i>
              User Management
            </NavLink>
          </li>
        )}

      </ul>
      <div className="mt-4">

  <p className="text-white text-center mb-2">
  {user?.name}
</p>

  <button
    className="btn btn-light w-100"
    onClick={handleLogout}
  >
    <span className="menu-text">Logout</span>
  </button>

</div>
    </div>
  );
}
